mapper.select:
SELECT t.id AS tagId, t.name, tr.weight
FROM tag_relationship tr
INNER JOIN tag t ON t.id = CASE WHEN tr.tag_id_1 = #{tagId} THEN tr.tag_id_2 ELSE tr.tag_id_1 END
WHERE tr.tag_id_1 = #{tagId} OR tr.tag_id_2 = #{tagId}
ORDER BY tr.weight DESC
LIMIT #{limit}

SELECT t.id AS tagId, t.name, COUNT(*) AS weight, 'read' AS source FROM article_tag at INNER JOIN tag t ON t.id = at.tag_id WHERE at.article_id IN
#{id}
GROUP BY t.id, t.name
